// Competidores a monitorear + queries de switching intent
const COMPETITOR_QUERIES = [
  // Queja directa a competidores
  { query: 'quejas colegios Quito problemas educación 2026', intent: 'switching', priority: 'hot' },
  { query: 'cambiar colegio Quito mejor opción educativa', intent: 'switching', priority: 'hot' },
  { query: 'colegio bilingue Quito malo problemas quejas', intent: 'dissatisfied', priority: 'hot' },
  // Búsqueda de alternativas
  { query: 'alternativas educativas Quito innovacion diferente', intent: 'exploring', priority: 'warm' },
  { query: 'por que cambiar de colegio educación tradicional anticuada', intent: 'awareness', priority: 'warm' },
  // Gap de Eight Academy vs competencia
  { query: 'colegio emprendimientos digitales tecnología Ecuador', intent: 'unique_feature', priority: 'warm' },
  { query: 'educación metaverso realidad virtual niños Ecuador', intent: 'unique_feature', priority: 'warm' },
  // Temporada de matrículas
  { query: 'cambio colegio inscripcion nueva matricula Quito 2026', intent: 'enrollment_switch', priority: 'hot' }
];

return COMPETITOR_QUERIES.map(q => ({ json: q }));

const aiResp = $input.first().json;
const rawText = aiResp.content?.[0]?.text || '{}';
const queryData = $('🔄 Loop Competitor Queries').first().json;

let ai = {};
try {
  const cleaned = rawText.replace(/```json/gi,'').replace(/```/gi,'').trim();
  ai = JSON.parse(cleaned);
} catch(e) {
  ai = { hot_leads_found: false, urgency: 'baja' };
}

return [{ json: {
  Semana: new Date().toISOString().split('T')[0],
  Query: queryData.query,
  Intent_Type: queryData.intent,
  Priority: queryData.priority,
  Hot_Leads_Found: ai.hot_leads_found || false,
  Switching_Signals: (ai.switching_signals || []).join(' | '),
  Target_Communities: (ai.target_communities || []).join(' | '),
  Ventaja_EA: ai.ea_competitive_advantage || '',
  Mensaje_Recomendado: ai.recommended_message || '',
  Urgencia: ai.urgency || 'baja',
  Competidores_Mencionados: (ai.competitors_mentioned || []).join(', '),
  Gap_Analysis: ai.gap_analysis || '',
  Acciones: (ai.action_items || []).join(' | '),
  _hot: ai.hot_leads_found && ai.urgency === 'alta',
  _msg: ai.recommended_message || ''
}}];

